import org.junit.jupiter.api.Test;

class SparqlUoBoundJoinRightArgOptimizerTest {

	@Test
	void learnedReorderUsesLiteralAnchoredSingleSharedBinding() {
		String query = String.join("\n",
				"PREFIX lib: <http://example.com/theme/library/>",
				"SELECT * WHERE {",
				"  ?book a lib:Book ; lib:writtenBy ?author ; lib:hasCopy ?copy .",
				"  ?copy lib:locatedAt ?branch .",
				"  ?loan a lib:Loan ; lib:loanedCopy ?copy ; lib:borrowedBy ?member .",
				"  OPTIONAL { ?member lib:name ?optName . }",
				"  FILTER(?optName IN (\"Member 1\", \"Member 2\", \"Member 3\"))",
				"}");

		TupleExpr tupleExpr = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null).getTupleExpr();
		EvaluationStatistics evaluationStatistics = new EvaluationStatistics();
		EmptyTripleSource tripleSource = new EmptyTripleSource();
		DefaultEvaluationStrategy strategy = new DefaultEvaluationStrategy(tripleSource, null, null, 0L,
				evaluationStatistics);
		RecordingLearnedQueryJoinOptimizer learnedJoinOptimizer = new RecordingLearnedQueryJoinOptimizer(
				evaluationStatistics, tripleSource);
		strategy.setOptimizerPipeline(new SparqlUoQueryOptimizerPipeline(strategy, tripleSource, evaluationStatistics,
				learnedJoinOptimizer, SparqlUoConfig.builder().allowNonImprovingTransforms(true).build()));

		strategy.optimize(tupleExpr, evaluationStatistics, EmptyBindingSet.getInstance());

		assertTrue(learnedJoinOptimizer.memberLiteralSeedSeen(),
				"Expected bound-right-arg learned optimization to run for member literal anchor.");
	}

	private static final class RecordingLearnedQueryJoinOptimizer extends LearnedQueryJoinOptimizer {

		private boolean memberLiteralSeedSeen;

		private RecordingLearnedQueryJoinOptimizer(EvaluationStatistics statistics, EmptyTripleSource tripleSource) {
			super(statistics, tripleSource, new MemoryJoinStats(MemoryJoinStats.InvalidationSettings.disabled()));
		}

		@Override
		public void optimize(TupleExpr tupleExpr, Dataset dataset, BindingSet bindings) {
			if (tupleExpr instanceof LeftJoin) {
				LeftJoin leftJoin = (LeftJoin) tupleExpr;
				if (leftJoin.getLeftArg() instanceof BindingSetAssignment) {
					Set<String> bindingNames = ((BindingSetAssignment) leftJoin.getLeftArg()).getBindingNames();
					if (bindingNames.contains("member") && bindingNames.contains("optName")) {
						memberLiteralSeedSeen = true;
					}
				}
			}
			super.optimize(tupleExpr, dataset, bindings);
		}

		private boolean memberLiteralSeedSeen() {
			return memberLiteralSeedSeen;
		}
	}
}
